import{_ as i,o as a,c as n,ak as o}from"./chunks/framework.CI25veif.js";const h=JSON.parse('{"title":"Migrate from v1","description":"","frontmatter":{"title":"Migrate from v1"},"headers":[],"relativePath":"articles/migrating-from-v1.md","filePath":"articles/migrating-from-v1.md"}'),t={name:"articles/migrating-from-v1.md"};function d(r,e,c,l,s,p){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="migrating-from-v1" tabindex="-1">Migrating from v1 <a class="header-anchor" href="#migrating-from-v1" aria-label="Permalink to “Migrating from v1”">​</a></h1><p>Version <code>2.x</code> changes the public API substantially.</p><h2 id="configuration-model" tabindex="-1">Configuration model <a class="header-anchor" href="#configuration-model" aria-label="Permalink to “Configuration model”">​</a></h2><p><code>ExternalAppConfiguration</code> was removed and replaced by <code>ExternalAppOptions</code>.</p><ul><li><code>Launch</code> contains startup and process-lifetime options.</li><li><code>Embedding</code> contains embedding mode, startup embedding behavior, and whether window chrome dimensions are compensated for during sizing.</li><li><code>Selection</code> contains timeout and polling behavior.</li></ul><p><code>Launch.Executable</code> can now be either a full path or a command name. <code>%VAR%</code> expansion is supported for both <code>Launch.Executable</code> and <code>Launch.WorkingDirectory</code>, and <code>Launch.EnvironmentVariables</code> can override values during expansion.</p><p>When <code>Launch.UseExistingProcess</code> is enabled, startup becomes discovery-only and skips process creation entirely.</p><h2 id="window-identification" tabindex="-1">Window identification <a class="header-anchor" href="#window-identification" aria-label="Permalink to “Window identification”">​</a></h2><p>Static matcher properties are no longer part of the library API.</p><ul><li>removed title matching</li><li>removed class-name matching</li><li>removed process-name matching</li><li>removed command-line matching</li><li>removed skip-count matching</li></ul><p>Instead, handle <code>WindowSelectionRequested</code> and select a window from the current <code>ExternalWindowCandidate</code> list.</p><p>The selection event now also provides:</p><ul><li><code>RequestedExecutablePath</code> to help correlate launcher stubs and process handoff scenarios</li><li><code>NewlyDiscoveredCandidates</code> to help prefer windows that appeared during the current start attempt</li></ul><p>Candidate windows also expose compatibility hints:</p><ul><li><code>PrefersExternalHosting</code></li><li><code>EmbeddingCompatibilityWarning</code></li></ul><p>Those hints indicate that the selected window may be a poor candidate for Win32 reparenting.</p><h2 id="native-dependency-removal" tabindex="-1">Native dependency removal <a class="header-anchor" href="#native-dependency-removal" aria-label="Permalink to “Native dependency removal”">​</a></h2><p>The library no longer ships or depends on <code>WinEmbed.dll</code>. Full-window and client-area embedding are implemented in managed code with Win32 interop.</p><p>There is no dedicated <code>EmbedMethod.External</code> in v2. If a selected window cannot be reparented, the library leaves it external, logs a warning, and keeps the session alive.</p>',19)])])}const g=i(t,[["render",d]]);export{h as __pageData,g as default};
